      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-03-01T14:00:00Z'), total: 20 }));
      orderRepo.save(makeOrder({ id: 'order-3', createdAt: new Date('2024-03-02T09:00:00Z'), total: 30 }));

      const points = service.getTrends('orders', new Date('2024-03-01'), new Date('2024-03-31'));

      expect(points).toHaveLength(2);
      expect(points[0]!.metric).toBe('orders');
      expect(points[0]!.value).toBe(2); // two orders on March 1
      expect(points[1]!.value).toBe(1); // one order on March 2
    });

    it('should return daily revenue trends', () => {
      orderRepo.save(makeOrder({ id: 'order-1', createdAt: new Date('2024-03-01T10:00:00Z'), total: 10 }));
      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-03-01T14:00:00Z'), total: 20 }));
