      orderRepo.save(makeOrder({ id: 'order-2', createdAt: new Date('2024-03-01T10:00:00Z'), total: 20 }));
      orderRepo.save(makeOrder({ id: 'order-3', createdAt: new Date('2024-03-03T10:00:00Z'), total: 30 }));

      const points = service.getTrends('orders', new Date('2024-03-01'), new Date('2024-03-31'));

      expect(points).toHaveLength(3);
      expect(points[0]!.timestamp).toEqual(new Date('2024-03-01'));
      expect(points[1]!.timestamp).toEqual(new Date('2024-03-03'));
      expect(points[2]!.timestamp).toEqual(new Date('2024-03-05'));
    });

    it('should throw for unsupported metric', () => {
      expect(() => service.getTrends('invalid', new Date('2024-03-01'), new Date('2024-03-31'))).toThrow(
